const e=`{% block sw_media_tag %} <div class="sw-media-tag"> <sw-media-collapse :title="$t('global.sw-tag-field.title')" :expand-on-loading="true" > {% block sw_media_tag_input %} <template #content> <sw-entity-tag-select v-model:entity-collection="media.tags" :disabled="disabled" @update:entity-collection="handleChange" /> </template> {% endblock %} </sw-media-collapse> </div> {% endblock %}`,t={template:e,inject:["repositoryFactory"],props:{media:{type:Object,required:!0},disabled:{type:Boolean,required:!1,default:!1}},computed:{mediaRepository(){return this.repositoryFactory.create("media")}},methods:{handleChange(){this.mediaRepository.save(this.media)}}};export{t as default};
